// ===== REGISTER NEW USER =====
{
  "firstName": "John",
  "lastName": "Doe",
  "email": "john.doe@example.com",
  "password": "password123"
}

// ===== EXISTING ACCOUNTS (Use Login instead) =====
// Admin: admin@example.com / admin123
// User:  user@example.com / user123

{
  "email": "{{test_email}}",
  "code": "1234",
  "amount": 999
}

// NOTES:
// - email (required): User's email address
// - code (required): 4-digit OTP from email
// - amount (optional): Payment amount in CENTS
//   * ⚠️ IMPORTANT: Always send amount in CENTS, not euros!
//   * If not provided, defaults to 999 cents (€9.99)
//   * Examples: 999 (€9.99), 1999 (€19.99), 2999 (€29.99)
//   * Backend converts cents to euros for database storage
//   * Always charged in EUR currency

{
  "email": "user@example.com"
}

// NOTES:
// - email (required): User's registered email address
// - OTP will be sent to this email
// - OTP is valid for 10 minutes

{
  "email": "user@example.com",
  "code": "1234"
}

// NOTES:
// - email (required): User's email address
// - code (required): 4-digit OTP from email
// - Replace '1234' with actual OTP from email
//
// RESPONSE:
// - resetToken: Temporary token (valid for 5 minutes)
// - Token is automatically saved for next step

{
  "resetToken": "{{reset_token}}",
  "newPassword": "NewPass123!"
}

// NOTES:
// - resetToken (required): Token from "Verify Reset OTP" step (automatically saved)
// - newPassword (required): New password (min 8 chars, uppercase, lowercase, number, special char)
//
// IMPORTANT: You MUST call "Verify Reset OTP" first to get the resetToken!
// The token is valid for 5 minutes only.
//
// PASSWORD REQUIREMENTS:
// - At least 8 characters
// - At least one uppercase letter (A-Z)
// - At least one lowercase letter (a-z)
// - At least one number (0-9)
// - At least one special character (@#$%^&*()_+-=[]{};\':"|,.<>/?)

{
  "amount": 999
}

// NOTES:
// - amount (optional): Payment amount in CENTS
//   * If not provided, defaults to 999 cents (€9.99)
//   * Examples: 999 = €9.99, 1999 = €19.99
//   * IMPORTANT: Send amount in CENTS not euros
//
// AUTH REQUIRED:
// - Bearer token in Authorization header
// - User must have status = PENDING (email verified, payment incomplete)
//
// USE CASE:
// - User verified OTP but cancelled/closed Stripe payment
// - User returns later and clicks "Complete Payment" button
// - Creates NEW Stripe session WITHOUT requiring OTP again
//
// FLOW DIFFERENCES:
// - OTP Verification → Creates payment session AFTER verifying code
// - This Endpoint → Creates payment session directly (no OTP needed)
//   * Because email already verified
//   * User just needs to complete payment

{
  "amount": 999
}

// NOTES:
// - amount (optional): Payment amount in CENTS
//   * If not provided, defaults to 999 cents (€9.99)
//   * Examples: 999 = €9.99, 1999 = €19.99
//   * Always in CENTS (frontend responsibility)
//
// AUTH REQUIRED: Bearer token in Authorization header

{
  "sessionId": "{{stripe_session_id}}"
}

// NOTES:
// - sessionId (required): Stripe checkout session ID
//   * Received from OTP verification response
//   * Or from create-checkout-session response
//   * Format: cs_test_xxxxxxxxxx

{
  "recipientEmail": "recipient@example.com",
  "recipientPassword": "GiftPass123!",
  "recipientFirstName": "John",
  "recipientLastName": "Doe",
  "amount": 999
}

// NOTES:
// - recipientEmail (required): Email for the new gift recipient account
// - recipientPassword (required): Password for recipient (min 8 chars, uppercase, lowercase, number, special char)
// - recipientFirstName (required): Recipient's first name
// - recipientLastName (required): Recipient's last name
// - amount (optional): Payment amount in CENTS (defaults to 999 cents = €9.99)
//   * ⚠️ IMPORTANT: Always send amount in CENTS, not euros!
//   * Examples: 999 (€9.99), 1999 (€19.99), 2999 (€29.99)
//
// AUTH REQUIRED: Bearer token of the gifter (logged-in user)
//
// PASSWORD REQUIREMENTS:
// - At least 8 characters
// - At least one uppercase letter
// - At least one lowercase letter
// - At least one number
// - At least one special character (@#$%^&*()_+-=[]{};\':"|,.<>/?)

{
  "sessionId": "{{stripe_session_id}}"
}

// NOTES:
// - sessionId (required): Stripe checkout session ID from gift checkout
//   * Received from create-gift-checkout-session response
//   * Format: cs_test_xxxxxxxxxx
//   * Extracted from success URL: ?session_id=cs_xxx&gift=true

{
  "currentPassword": "password123",
  "newPassword": "newPassword456",
  "firstName": "John",
  "lastName": "Doe"
}

// REQUIRED FIELDS:
// - currentPassword: Current password for verification
// - newPassword: New password (min 8 characters)
//
// OPTIONAL FIELDS:
// - firstName: Update first name
// - lastName: Update last name
//
// NOTE:
// - Email cannot be changed
// - Both passwords are required
// - Password must be at least 8 characters

{
  "homeAirport": "LAX"
}

// REQUIRED FIELD:
// - homeAirport: Airport code (e.g., LAX, JFK, LHR)
//
// NOTE:
// - No password verification required for airport update
// - Separate endpoint for easier frontend integration

{
  "firstName": "John",
  "lastName": "Doe",
  "homeAirport": "LAX",
  "status": "ACTIVE",
  "role": "USER"
}

// ALL FIELDS OPTIONAL:
// - firstName: Update first name
// - lastName: Update last name
// - homeAirport: Update home airport code
// - status: Update status (ACTIVE or INACTIVE)
// - role: Update role (USER/ADMIN)
//
// NOTE:
// - Admin can update any field without password
// - Email cannot be changed
// - password cannot be changed (user must do it themselves)

{
  "fullName": "John Doe",
  "email": "john.doe@example.com",
  "message": "Hi, I have a question about your travel deals. Can you provide more information about the annual membership benefits?"
}

// REQUIRED FIELDS:
// - fullName (string): Sender's full name
// - email (string): Valid email address
// - message (string): Message content (10-1000 characters)
//
// VALIDATION:
// - Email format is validated
// - Message must be at least 10 characters
// - Message must not exceed 1000 characters
//
// NOTE: No authentication required (public endpoint)
